TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- Caso INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_INTERCONSULTAS WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_INTERCONSULTAS WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_INTERCONSULTAS ( ENVIO_BQ, ID, FECHA_CREACION, ID_SOLICITUD_SERVICIO, ID_ESPECIALIDAD_INTERCONSULTA, ID_PROFESIONAL_INTERCONSULTA, CLASE_INTERCONSULTA, ID_PROFESIONAL_ENTIDAD_SOL, URL_ZOOM_INVITADO, URL_ZOOM_HOST, ID_CUENTA_ZOOM, ID_REUNION_ZOOM, CLAVE_ZOOM, ID_HEXADECIMAL, DIAGNOSTICO_PRINCIPAL, ID_PROFESIONAL_TEKER_SOL, RESUMEN_INTERCONSULTA, COMENTARIOS_INTERCONSULTA, RESUMEN_CASO ) VALUES ( 0, -- ENVIO_BQ para INSERT :NEW.ID, :NEW.FECHA_CREACION, :NEW.ID_SOLICITUD_SERVICIO, :NEW.ID_ESPECIALIDAD_INTERCONSULTA, :NEW.ID_PROFESIONAL_INTERCONSULTA, :NEW.CLASE_INTERCONSULTA, :NEW.ID_PROFESIONAL_ENTIDAD_SOL, :NEW.URL_ZOOM_INVITADO, :NEW.URL_ZOOM_HOST, :NEW.ID_CUENTA_ZOOM, :NEW.ID_REUNION_ZOOM, :NEW.CLAVE_ZOOM, :NEW.ID_HEXADECIMAL, :NEW.DIAGNOSTICO_PRINCIPAL, :NEW.ID_PROFESIONAL_TEKER_SOL, :NEW.RESUMEN_INTERCONSULTA, :NEW.COMENTARIOS_INTERCONSULTA, :NEW.RESUMEN_CASO ); END IF;
-- Caso UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_INTERCONSULTAS WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_INTERCONSULTAS ( ENVIO_BQ, ID, FECHA_CREACION, ID_SOLICITUD_SERVICIO, ID_ESPECIALIDAD_INTERCONSULTA, ID_PROFESIONAL_INTERCONSULTA, CLASE_INTERCONSULTA, ID_PROFESIONAL_ENTIDAD_SOL, URL_ZOOM_INVITADO, URL_ZOOM_HOST, ID_CUENTA_ZOOM, ID_REUNION_ZOOM, CLAVE_ZOOM, ID_HEXADECIMAL, DIAGNOSTICO_PRINCIPAL, ID_PROFESIONAL_TEKER_SOL, RESUMEN_INTERCONSULTA, COMENTARIOS_INTERCONSULTA, RESUMEN_CASO ) VALUES ( 2, -- ENVIO_BQ para INSERT :NEW.ID, :NEW.FECHA_CREACION, :NEW.ID_SOLICITUD_SERVICIO, :NEW.ID_ESPECIALIDAD_INTERCONSULTA, :NEW.ID_PROFESIONAL_INTERCONSULTA, :NEW.CLASE_INTERCONSULTA, :NEW.ID_PROFESIONAL_ENTIDAD_SOL, :NEW.URL_ZOOM_INVITADO, :NEW.URL_ZOOM_HOST, :NEW.ID_CUENTA_ZOOM, :NEW.ID_REUNION_ZOOM, :NEW.CLAVE_ZOOM, :NEW.ID_HEXADECIMAL, :NEW.DIAGNOSTICO_PRINCIPAL, :NEW.ID_PROFESIONAL_TEKER_SOL, :NEW.RESUMEN_INTERCONSULTA, :NEW.COMENTARIOS_INTERCONSULTA, :NEW.RESUMEN_CASO );
ELSE
IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_INTERCONSULTAS SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, FECHA_CREACION = :NEW.FECHA_CREACION, ID_SOLICITUD_SERVICIO = :NEW.ID_SOLICITUD_SERVICIO, ID_ESPECIALIDAD_INTERCONSULTA = :NEW.ID_ESPECIALIDAD_INTERCONSULTA, ID_PROFESIONAL_INTERCONSULTA = :NEW.ID_PROFESIONAL_INTERCONSULTA, CLASE_INTERCONSULTA = :NEW.CLASE_INTERCONSULTA, ID_PROFESIONAL_ENTIDAD_SOL = :NEW.ID_PROFESIONAL_ENTIDAD_SOL, URL_ZOOM_INVITADO = :NEW.URL_ZOOM_INVITADO, URL_ZOOM_HOST = :NEW.URL_ZOOM_HOST, ID_CUENTA_ZOOM = :NEW.ID_CUENTA_ZOOM, ID_REUNION_ZOOM = :NEW.ID_REUNION_ZOOM, CLAVE_ZOOM = :NEW.CLAVE_ZOOM, ID_HEXADECIMAL = :NEW.ID_HEXADECIMAL, DIAGNOSTICO_PRINCIPAL = :NEW.DIAGNOSTICO_PRINCIPAL, ID_PROFESIONAL_TEKER_SOL = :NEW.ID_PROFESIONAL_TEKER_SOL, RESUMEN_INTERCONSULTA = :NEW.RESUMEN_INTERCONSULTA, COMENTARIOS_INTERCONSULTA = :NEW.COMENTARIOS_INTERCONSULTA, RESUMEN_CASO = :NEW.RESUMEN_CASO WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_INTERCONSULTAS WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_INTERCONSULTAS WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_INTERCONSULTAS ( ENVIO_BQ, ID, FECHA_CREACION, ID_SOLICITUD_SERVICIO, ID_ESPECIALIDAD_INTERCONSULTA, ID_PROFESIONAL_INTERCONSULTA, CLASE_INTERCONSULTA, ID_PROFESIONAL_ENTIDAD_SOL, URL_ZOOM_INVITADO, URL_ZOOM_HOST, ID_CUENTA_ZOOM, ID_REUNION_ZOOM, CLAVE_ZOOM, ID_HEXADECIMAL, DIAGNOSTICO_PRINCIPAL, ID_PROFESIONAL_TEKER_SOL, RESUMEN_INTERCONSULTA, COMENTARIOS_INTERCONSULTA, RESUMEN_CASO ) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.FECHA_CREACION, :OLD.ID_SOLICITUD_SERVICIO, :OLD.ID_ESPECIALIDAD_INTERCONSULTA, :OLD.ID_PROFESIONAL_INTERCONSULTA, :OLD.CLASE_INTERCONSULTA, :OLD.ID_PROFESIONAL_ENTIDAD_SOL, :OLD.URL_ZOOM_INVITADO, :OLD.URL_ZOOM_HOST, :OLD.ID_CUENTA_ZOOM, :OLD.ID_REUNION_ZOOM, :OLD.CLAVE_ZOOM, :OLD.ID_HEXADECIMAL, :OLD.DIAGNOSTICO_PRINCIPAL, :OLD.ID_PROFESIONAL_TEKER_SOL, :OLD.RESUMEN_INTERCONSULTA, :OLD.COMENTARIOS_INTERCONSULTA, :OLD.RESUMEN_CASO ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_INTERCONSULTAS'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error); END;
